1	import { quote, claim, type Customer, type Item, type Incident } from "./claim-office.js";
2	
3	export interface CliResult {
4	  stdout: string;
5	  stderr: string;
6	  exitCode: number;
7	}
8	
9	interface QuoteStep {
10	  op?: "quote";
11	  items: Item[];
12	}
13	
14	interface ClaimStep {
15	  op: "claim";
16	  policy: number;
17	  incident: Incident;
18	}
19	
20	type Step = QuoteStep | ClaimStep;
21	
22	interface Scenario {
23	  customer: Customer;
24	  steps: Step[];
25	}
26	
27	export function runScenario(scenarioJson: string): CliResult {
28	  const scenario: Scenario = JSON.parse(scenarioJson);
29	  const results = scenario.steps.map((step) => {
30	    if (step.op === "claim") {
31	      const policyStep = scenario.steps[step.policy] as QuoteStep;
32	      return claim({ items: policyStep.items }, step.incident);
33	    }
34	    return { premium: quote(scenario.customer, (step as QuoteStep).items) };
35	  });
36	  return { stdout: JSON.stringify({ results }), stderr: "", exitCode: 0 };
37	}
